-- France – Student Visa (VLS-TS) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee student visa approval?","a":"No. Embassy decides based on admission, funds, and credibility. Never promise approval."},{"q":"What is APS?","a":"Academic Evaluation Centre verification for Indian academic documents—mandatory for most Indian student visa applicants."},{"q":"Proof of funds amount for 2026?","a":"Typically required living funds (12 months × €992). Verify current amount before opening account."},{"q":"Can spouse accompany?","a":"Dependants may apply separately; prove additional funds and accommodation. Assess case-by-case."},{"q":"English-taught programs need French?","a":"Depends on program—follow admission and embassy requirements."},{"q":"How long to convert to residence permit?","a":"Apply at Ausländerbehörde soon after arrival and registration."},{"q":"Can I work on student visa?","a":"Limited working hours permitted—verify current rules for students in Frenchy."},{"q":"What after graduation?","a":"Discuss 18-month job-seeker residence permit or Opportunity Card separately."},{"q":"What is Description for this service?","a":"National visa (Type D) for study at a recognised French university or preparatory course. After entry, convert to residence permit at local Ausländerbehörde."},{"q":"What is Eligible applicants for this service?","a":"University admission (Zulassung) or conditional admission · Proof of funds or scholarship · admission documentation (India) · Health insurance · Motivation letter"},{"q":"What is Proof of funds for this service?","a":"required living funds for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"Important note on Proof of funds?","a":"required living funds for 2026 (12 × €992/month) typically required unless scholarship or sponsor alternative applies."},{"q":"What is Key authority for this service?","a":"French Embassy/Consulate in India · Federal Foreign Office · Local Ausländerbehörde after arrival"},{"q":"What is After approval for this service?","a":"Enter Frenchy; register address; apply for residence permit at Ausländerbehörde within visa validity."},{"q":"Is Admission from recognised French institution required?","a":"Admission from recognised French institution is typically required."},{"q":"Is admission documentation (India) required?","a":"Apply early—processing takes weeks"},{"q":"Is Proof of funds or financial proof required?","a":"required living funds for 2026 or equivalent"},{"q":"Is Health insurance (travel + statutory) required?","a":"Assess whether Health insurance (travel + statutory) is satisfied for this case."},{"q":"Is Motivation letter and CV required?","a":"Motivation letter and CV is typically required."},{"q":"Is Language proficiency (as required) required?","a":"French or English per program"},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"What is the Processing time?","a":"6–12w — After complete file + APS"},{"q":"What is the Government fee?","a":"€75 — + proof of funds required living funds"},{"q":"What is the Our approval rate?","a":"88% — ~74% benchmark"},{"q":"What is the Required docs?","a":"15 — + APS & proof of funds"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & third-party"},{"q":"What if the client has APS not completed?","a":"Complete APS before embassy slot; track processing on APS website"},{"q":"Why is APS not completed a problem?","a":"Visa appointment booked without admission documentation."},{"q":"What if the client has Insufficient proof of funds?","a":"Open proof of funds at approved bank for full required amount"},{"q":"Why is Insufficient proof of funds a problem?","a":"Amount below required monthly sum or not from recognised provider."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000081'::uuid;

-- France – Schengen Visitor Visa (Type C) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Schengen approval?","a":"No. Consulate decides each application individually."},{"q":"Which embassy to apply?","a":"Country of main destination or first entry if equal stays—follow Schengen rules."},{"q":"How much travel insurance?","a":"Minimum €30,000 medical coverage valid across Schengen for entire trip."},{"q":"Can I visit multiple Schengen countries?","a":"Yes on single visa if main destination rule followed; respect 90/180 limit."},{"q":"How long processing?","a":"Typically 2–4 weeks; apply well before travel date."},{"q":"Does prior UK/US refusal affect Schengen?","a":"Must disclose; consulate considers overall immigration history."},{"q":"Can visitor work?","a":"No. Employment not permitted on Schengen short-stay visa."},{"q":"Reapply after refusal?","a":"Yes when circumstances improve; address prior refusal grounds."},{"q":"What is Description for this service?","a":"Schengen Type C short-stay visa for tourism, family visits, or business trips to Frenchy up to 90 days per 180-day period."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Travel insurance €30,000+ · Funds for trip · Strong ties to India · Clean Schengen history"},{"q":"What is Main destination rule for this service?","a":"Apply at embassy of main Schengen destination. If Frenchy is primary stay, apply via French mission."},{"q":"Important note on Main destination rule?","a":"Apply at embassy of main Schengen destination. If Frenchy is primary stay, apply via French mission."},{"q":"What is Key authority for this service?","a":"French Embassy/Consulate · VFS Global (appointment partner in India)"},{"q":"What is After approval for this service?","a":"Respect visa validity and 90/180 rule. Overstay affects future Schengen applications."},{"q":"Is Valid passport (3+ months beyond stay) required?","a":"Valid passport (3+ months beyond stay) is typically required."},{"q":"Is Travel medical insurance €30,000+ required?","a":"Valid for entire Schengen stay"},{"q":"Is Proof of accommodation and itinerary required?","a":"Proof of accommodation and itinerary is typically required."},{"q":"Is Proof of funds required?","a":"Proof of funds is typically required."},{"q":"Is Strong ties to India required?","a":"Strong ties to India is typically required."},{"q":"Is Cover letter explaining purpose required?","a":"Cover letter explaining purpose is typically required."},{"q":"Is Biometrics (if not in VIS) required?","a":"Assess whether Biometrics (if not in VIS) is satisfied for this case."},{"q":"What is the Processing time?","a":"2–4w — Schengen standard"},{"q":"What is the Government fee?","a":"€90 — Adult Schengen visa"},{"q":"What is the Our approval rate?","a":"76% — ~64% benchmark"},{"q":"What is the Required docs?","a":"10 — + travel insurance"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient travel insurance?","a":"Purchase Schengen-compliant insurance for full trip dates"},{"q":"Why is Insufficient travel insurance a problem?","a":"Coverage below €30,000 or wrong dates."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-000000000082'::uuid;

