-- Ireland – Stamp 2 Student Permission — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Student visa approval?","a":"No. Irish Immigration Service Delivery assesses each application. Strong CAS and funds help but approval is never guaranteed."},{"q":"How much funds for London vs outside London?","a":"Living costs differ—verify current amounts on irishimmigration.ie. Plus remaining tuition after deposit shown on CAS."},{"q":"What is the 28-day rule?","a":"Funds must remain at or above required amount for 28 consecutive days ending no more than 31 days before application."},{"q":"Can spouse join on Student visa?","a":"Dependants allowed only if course meets specific criteria (e.g., postgraduate level certain duration). Check current rules."},{"q":"Is IELTS Irish Immigration Service Delivery mandatory?","a":"If SELT required, must be Irish Immigration Service Delivery-approved test from approved centre. Some nationals/courses may be exempt."},{"q":"When to apply?","a":"Up to 6 months before course start if applying from outside Ireland. Do not apply without valid CAS."},{"q":"Can student work?","a":"Limited hours during term; rules on irishimmigration.ie. Cannot work as professional sportsperson or doctor in training."},{"q":"What after course completion?","a":"Discuss Graduate Route eligibility separately—requires successful completion at eligible institution."},{"q":"What is Description for this service?","a":"Student Route visa for study at a Ireland institution holding a valid sponsor licence. Requires Confirmation of Acceptance for Studies (CAS) and online Irish Immigration Service Delivery application."},{"q":"What is Eligible applicants for this service?","a":"Valid CAS · Proof of funds · English at required level · Genuine student intent · TB test if from listed country"},{"q":"What is Financial requirement for this service?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"Important note on Financial requirement?","a":"Tuition minus deposit paid + living costs (London vs outside London rates). 28-day funds rule applies."},{"q":"What is Key authority for this service?","a":"Ireland Visas and Immigration (Irish Immigration Service Delivery) — Home Office"},{"q":"What is After approval for this service?","a":"BRP or digital status; maintain attendance, sponsor reporting, and work hour limits."},{"q":"Is CAS from licensed Ireland sponsor required?","a":"CAS number valid and unused"},{"q":"Is Financial requirement met (28-day rule) required?","a":"Funds held 28 consecutive days"},{"q":"Is English language at SELT level (if required) required?","a":"IELTS Irish Immigration Service Delivery or exempt pathway"},{"q":"Is TB test certificate (if applicable) required?","a":"Required for Indian nationals"},{"q":"Is ATAS certificate (if course requires) required?","a":"Check CAS and course code"},{"q":"Is Genuine student / credible study plan required?","a":"Genuine student / credible study plan is typically required."},{"q":"Is Immigration history disclosed required?","a":"Immigration history disclosed is typically required."},{"q":"What is the Processing time?","a":"3–8w — Outside Ireland standard"},{"q":"What is the Government fee?","a":"€60+ (verify current fee) — + IHS per year of course"},{"q":"What is the Our approval rate?","a":"89% — ~76% industry benchmark"},{"q":"What is the Required docs?","a":"13 — + financial evidence"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & IHS"},{"q":"What if the client has 28-day funds rule breach?","a":"Maintain required balance 28 days; use dated bank statements"},{"q":"Why is 28-day funds rule breach a problem?","a":"Funds not held continuously for 28 days or balance drops below threshold."},{"q":"What if the client has CAS / course mismatch?","a":"Align CAS course with academic progression; strong personal statement"},{"q":"Why is CAS / course mismatch a problem?","a":"Course level inconsistent with prior study or career plan."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000a3'::uuid;

-- Ireland – Short Stay Visit Visa (C) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee visitor visa approval?","a":"No. Irish Immigration Service Delivery decides each case on merits. We strengthen documentation but never promise approval."},{"q":"How much funds to show?","a":"Enough to cover flights, accommodation, and daily expenses. No fixed amount—must be credible for trip duration."},{"q":"Is invitation letter required?","a":"Recommended for family visits. Host should provide invitation, status proof, and accommodation details."},{"q":"Can visitor switch to student visa in Ireland?","a":"Generally cannot switch from visitor to student inside Ireland—apply from outside. Verify current rules."},{"q":"How long can visitor stay?","a":"Usually up to up to 90 days (verify stamp) on standard visitor visa. Officer may grant shorter period."},{"q":"Does prior Schengen refusal affect Ireland visa?","a":"Must disclose all refusals. Irish Immigration Service Delivery considers overall immigration history."},{"q":"Can visitor work?","a":"No paid or unpaid work except limited permitted business visitor activities."},{"q":"Priority service available?","a":"Check irishimmigration.ie for current priority/super priority options and VAC availability in India."},{"q":"What is Description for this service?","a":"Standard Visitor visa for tourism, visiting family/friends, or short business activities in the Ireland. Most Indian applicants apply online and attend VAC biometrics."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Funds for trip · Strong ties to India · Genuine intention to leave Ireland · Clean immigration history"},{"q":"What is No work or long-term study for this service?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"Important note on No work or long-term study?","a":"Visitors cannot work or access public funds. Short courses up to 6 months may be permitted—verify rules."},{"q":"What is Key authority for this service?","a":"Ireland Visas and Immigration (Irish Immigration Service Delivery) — Home Office"},{"q":"What is After approval for this service?","a":"Visa vignette in passport; entry decision at border. Respect visit duration—overstay affects future applications."},{"q":"Is Valid passport required?","a":"Valid passport is typically required."},{"q":"Is Clear visit purpose required?","a":"Tourism, family, or permitted business activity"},{"q":"Is Proof of funds required?","a":"Cover trip cost or credible sponsor"},{"q":"Is Strong ties to India required?","a":"Employment, business, property, family"},{"q":"Is Accommodation and travel plans required?","a":"Itinerary or host invitation"},{"q":"Is Biometrics completed required?","a":"Assess whether Biometrics completed is satisfied for this case."},{"q":"Is No prior immigration breaches undisclosed required?","a":"No prior immigration breaches undisclosed is typically required."},{"q":"What is the Processing time?","a":"3–6w — Standard visitor outside Ireland"},{"q":"What is the Government fee?","a":"£115 — 6-month visit (2026)"},{"q":"What is the Our approval rate?","a":"74% — ~62% industry benchmark"},{"q":"What is the Required docs?","a":"9 — + invitation if applicable"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt only"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient funds?","a":"Bank history, ITR, sponsor letter with host support if applicable"},{"q":"Why is Insufficient funds a problem?","a":"Cannot explain trip funding or recent large deposits."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000a4'::uuid;

