-- Spain – Schengen Visitor Visa (Type C) — 30 FAQs
UPDATE public.service_library
SET academy_metadata = jsonb_set(
  COALESCE(academy_metadata, '{}'::jsonb),
  '{faqs}',
  '[{"q":"Can we guarantee Schengen approval?","a":"No. Consulate decides each application individually."},{"q":"Which embassy to apply?","a":"Country of main destination or first entry if equal stays—follow Schengen rules."},{"q":"How much travel insurance?","a":"Minimum €30,000 medical coverage valid across Schengen for entire trip."},{"q":"Can I visit multiple Schengen countries?","a":"Yes on single visa if main destination rule followed; respect 90/180 limit."},{"q":"How long processing?","a":"Typically 2–4 weeks; apply well before travel date."},{"q":"Does prior UK/US refusal affect Schengen?","a":"Must disclose; consulate considers overall immigration history."},{"q":"Can visitor work?","a":"No. Employment not permitted on Schengen short-stay visa."},{"q":"Reapply after refusal?","a":"Yes when circumstances improve; address prior refusal grounds."},{"q":"What is Description for this service?","a":"Schengen Type C short-stay visa for tourism, family visits, or business trips to Spanishy up to 90 days per 180-day period."},{"q":"What is Eligible applicants for this service?","a":"Temporary visit purpose · Travel insurance €30,000+ · Funds for trip · Strong ties to India · Clean Schengen history"},{"q":"What is Main destination rule for this service?","a":"Apply at embassy of main Schengen destination. If Spanishy is primary stay, apply via Spanish mission."},{"q":"Important note on Main destination rule?","a":"Apply at embassy of main Schengen destination. If Spanishy is primary stay, apply via Spanish mission."},{"q":"What is Key authority for this service?","a":"Spanish Embassy/Consulate · VFS Global (appointment partner in India)"},{"q":"What is After approval for this service?","a":"Respect visa validity and 90/180 rule. Overstay affects future Schengen applications."},{"q":"Is Valid passport (3+ months beyond stay) required?","a":"Valid passport (3+ months beyond stay) is typically required."},{"q":"Is Travel medical insurance €30,000+ required?","a":"Valid for entire Schengen stay"},{"q":"Is Proof of accommodation and itinerary required?","a":"Proof of accommodation and itinerary is typically required."},{"q":"Is Proof of funds required?","a":"Proof of funds is typically required."},{"q":"Is Strong ties to India required?","a":"Strong ties to India is typically required."},{"q":"Is Cover letter explaining purpose required?","a":"Cover letter explaining purpose is typically required."},{"q":"Is Biometrics (if not in VIS) required?","a":"Assess whether Biometrics (if not in VIS) is satisfied for this case."},{"q":"What is the Processing time?","a":"2–4w — Schengen standard"},{"q":"What is the Government fee?","a":"€90 — Adult Schengen visa"},{"q":"What is the Our approval rate?","a":"76% — ~64% benchmark"},{"q":"What is the Required docs?","a":"10 — + travel insurance"},{"q":"What is the Consultancy fee?","a":"See fee tab — + govt & insurance"},{"q":"What if the client has Weak ties to India?","a":"Employment letter, business proof, property, family obligations"},{"q":"Why is Weak ties to India a problem?","a":"Unemployed, no assets, vague return plan."},{"q":"What if the client has Insufficient travel insurance?","a":"Purchase Schengen-compliant insurance for full trip dates"},{"q":"Why is Insufficient travel insurance a problem?","a":"Coverage below €30,000 or wrong dates."}]'::jsonb
), updated_at = now()
WHERE id = 'b2000001-0001-4000-8000-0000000000a6'::uuid;

